package br.com.portfolio.ecommerce.catalog.infrastructure.persistence;
import br.com.portfolio.ecommerce.catalog.application.port.out.ProductRepository; import br.com.portfolio.ecommerce.catalog.domain.Product; import br.com.portfolio.ecommerce.shared.domain.Money; import org.springframework.stereotype.Repository; import java.util.*;
@Repository public class ProductRepositoryAdapter implements ProductRepository { private final ProductJpaRepository repo; public ProductRepositoryAdapter(ProductJpaRepository repo){this.repo=repo;} public Optional<Product> findById(UUID id){return repo.findById(id).map(this::map);} public List<Product> findActive(){return repo.findByActiveTrue().stream().map(this::map).toList();} private Product map(ProductJpaEntity e){return new Product(e.getId(),e.getSku(),e.getName(),new Money(e.getPrice()),e.isActive());} }
